class Solution:
    def baseNeg2(self, n: int) -> str:
        if n == 0:
            return '0'
        res = []
        while n:
            n, r = divmod(n, -2)
            if r < 0:
                n, r = n + 1, r + 2
            res.append(str(r))
        return ''.join(res[::-1])
